using HRMS.Domain.Enums;
namespace HRMS.Application.Modules.Recruitment.DTOs;
public class JobVacancyDto { public Guid Id { get; set; } public string Code { get; set; } = string.Empty; public string Title { get; set; } = string.Empty; public string? Description { get; set; } public Guid? DepartmentId { get; set; } public string? DepartmentName { get; set; } public int NumberOfPositions { get; set; } public DateTime PostedDate { get; set; } public DateTime? ClosingDate { get; set; } public RecruitmentStatus Status { get; set; } public decimal? MinSalary { get; set; } public decimal? MaxSalary { get; set; } public string? Requirements { get; set; } public DateTime CreatedAt { get; set; } }
public class CandidateDto { public Guid Id { get; set; } public Guid JobVacancyId { get; set; } public string? JobTitle { get; set; } public string FirstName { get; set; } = string.Empty; public string LastName { get; set; } = string.Empty; public string FullName => $"{FirstName} {LastName}"; public string Email { get; set; } = string.Empty; public string? Phone { get; set; } public string? ResumeUrl { get; set; } public string ApplicationStatus { get; set; } = string.Empty; public DateTime ApplicationDate { get; set; } public DateTime CreatedAt { get; set; } }
public class InterviewDto { public Guid Id { get; set; } public Guid CandidateId { get; set; } public string? CandidateName { get; set; } public DateTime ScheduledDate { get; set; } public string InterviewType { get; set; } = string.Empty; public string? Location { get; set; } public string Status { get; set; } = string.Empty; public string? Feedback { get; set; } public int? Rating { get; set; } public DateTime CreatedAt { get; set; } }
